good-example.code-block:
package com.example.orders.events;

// Good: stable event type, explicit schema version, keyed by aggregate id
public record OrderCreatedEvent(
    String eventId,
    String schemaVersion,
    String orderId,
    String customerId
) {}
// topic: orders.events.v1
// key: orderId (keeps order-specific ordering within a partition)

