package com.example.orders.messaging;

import com.example.orders.events.OrderCreatedEvent;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.stereotype.Component;

@Component
class BadOrderEventListener {
    @KafkaListener(topics = "orders.events.v1")
    void onEvent(OrderCreatedEvent event) {
        // Bad: swallow exception and lose observability / delivery guarantees
        try {
            // process(event);
            throw new RuntimeException("Failed");
        } catch (Exception ignored) {
